{"content": "import { loadBlogPost } from '../../../../lib/page-data'
import SectionsRenderer from '../../../../components/SectionsRenderer'
import type { Metadata } from 'next'
import { Header } from '../../../../components/Header'
import { Footer } from '../../../../components/Footer'

interface Props { params: Promise<{ locale: string; slug: string }> }

export async function generateMetadata({ params }: Props): Promise<Metadata> {
  const { locale, slug } = await params
  const data = loadBlogPost(locale, slug)
  if (!data || !data.post) return {}
  return { title: data.post.title, description: data.post.excerpt || '' }
}

export default async function BlogPostPage({ params }: Props) {
  const { locale, slug } = await params
  const data = loadBlogPost(locale, slug)
  if (!data || !data.post) return <div>Post not found</div>
  const { content, post } = data
  return (
    <div style={{ fontFamily: "'Inter', sans-serif", color: '#1B2A4A' }}>
      {content?.navigation && <Header navigation={content.navigation} locale={locale} />}
      <main style={{ maxWidth: 750, margin: '0 auto', padding: '3rem 1rem' }}>
        <h1 style={{ fontSize: '2rem', fontWeight: 700 }}>{post.title}</h1>
        {post.date && <p style={{ color: '#C9A96E', fontSize: '0.85rem' }}>{post.date}</p>}
        {post.excerpt && <p style={{ fontStyle: 'italic', color: '#555' }}>{post.excerpt}</p>}
        <div style={{ lineHeight: 1.8, color: '#444' }}>{post.body?.split('\\n').map((p: string, i: number) => <p key={i} style={{ marginBottom: '1rem' }}>{p}</p>)}</div>
      </main>
      {content?.footer && <Footer footer={content.footer} />}
    </div>
  )
}

