{"content": "import { Suspense } from 'react'
import { loadBlogPost } from '../../../../lib/page-data'
import { Header } from '../../../../components/Header'
import { Footer } from '../../../../components/Footer'
import type { Metadata } from 'next'

interface Props { params: Promise<{ locale: string; slug: string }> }

const LOCALES = ['es', 'en', 'nl', 'de']

export function generateStaticParams() {
  const params: { locale: string; slug: string }[] = []
  const { existsSync, readdirSync } = require('fs')
  const { join } = require('path')
  for (const locale of LOCALES) {
    const blogDir = join(process.cwd(), 'content', 'blog', locale)
    if (existsSync(blogDir)) {
      const slugs = readdirSync(blogDir).filter((f: string) => f.endsWith('.mdx')).map((f: string) => f.replace('.mdx', ''))
      for (const slug of slugs) params.push({ locale, slug })
    }
  }
  return params
}

export function generateMetadata({ params }: Props): Metadata {
  return { title: 'Nexa Paraguay' }
}

function BlogSkeleton() {
  return (
